INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (130, '1.', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (130, '2.', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (130, '3.', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (130, '4.', 'Ahlaki ve etik değerlere uygun davranır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (131, '5.', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (131, '6.', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (131, '7.', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (131, '8.', 'Her türlü iletişimde empati kurmaya özen gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (132, '9.', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (132, '10.', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (132, '11.', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (132, '12.', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (133, '13.', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (133, '14.', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (133, '15.', 'Yapılan işin kalitesini sürekli geliştirmek yönünde çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (133, '16.', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (134, '17.', 'Çalışma ortamında iyi ilişkiler kurar ve korur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (134, '18.', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (134, '19.', 'Takım ruhuna uyumlu yaklaşımda bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (134, '20.', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (135, '21.', 'İşlerin hatasız tamamlanması için çaba sarf eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (135, '22.', 'Küçük detaylara dikkat eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (135, '23.', 'İşin inceliklerini öğrenmek ve işin bütününe hâkim olabilmek için sürekli gözlem yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (135, '24.', 'Hataları, iş çıktıları paylaşılmadan fark eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (136, '25.', 'İş ortamında; kızgınlık, korku, kaygı, üzüntü, depresyon, vb. duygularını kontrol eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (136, '26.', 'Özel hayatında yaşadığı sıkıntıları, iş ortamına en az ölçüde yansıtır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (136, '27.', 'Zor çalışma koşullarında ve yoğun mesaide bile başarılı sonuçlar elde edebilir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (137, '28.', 'Mesleki motivasyonu yüksektir ve işini severek yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (137, '29.', 'Kendisine verilen işleri takip eder, doğru, eksiksiz ve zamanında sonuçlandırır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (137, '30.', 'Her zaman daha iyisini yapmak adına kendisini sürekli geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (138, '1.', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (138, '2.', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (138, '3.', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (138, '4.', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '5.', 'Ürünleri reçetelere uygun hazırlar. Ürünlerin her seferinde aynı kalite ve tatta olmasını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '6.', 'Et pişirme tekniklerine hakimdir. Şirket standartlarına uygun pişirme yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '7.', 'Patates kızartma standartlarını bilir, doğru şekilde uygular.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '8.', 'Peynir çubukları, soğan halkası, nugget vb. ürünleri doğru sürede uygun sıcaklıkta pişirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '9.', 'Ekmek kesimini ve burger süslemesini standartlara uygun olarak yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '10.', 'Kızartma yağı TPM ölçümünü doğru olarak yapar.İç ısı standardını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (139, '11.', 'Yağ filtre işlemini standartlara uygun olarak yapar. Koruyucu materyalleri kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '12.', 'Ürünlerin son kullanma tarihine dikkat eder. Zayii olmasına izin vermez. (FIFO-İlk Giren İlk Çıkar)');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '13.', 'Sebzeleri standartlara uygun şekilde yıkar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '14.', 'Küçük ekipmanların hijyenini standartlara uygun olarak sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '15.', 'Gıda güvenliği ve operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '16.', 'Temizlik kimyasallarını İSG kurallarına uygun şekilde kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (140, '17.', 'Çalışma süresince İSG kurallarına uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (141, '18.', 'İstasyonlarda doğru ürün miktarının bulunmasına özen gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (141, '19.', 'Çalıştığı istasyonların temizliğini ve düzenini sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (141, '20.', 'Çalıştığı ekipmanları özenli ve titiz kullanır. Temizliğini yapar.');

